use std::thread;

struct GameState {
    record_id: u32,
}

fn process_replay_data(_state: GameState, thread_name: &str) -> i32 {
    let mut local_counter = 0;
    let mut thread_specific_log = Vec::new();

    unsafe { 
        thread_local! { 
            static PROCESSOR_STATE: std::cell::Cell<i32> = std::cell::Cell::new(0);
        }
        PROCESSOR_STATE.with(|cell| {
            let current_val = cell.get();
            println!("n[Worker Thread] Starting processing for {}.", thread_name);
            local_counter = current_val + 1;
            thread_specific_log.push(format!("Initialized counter to {}", local_counter));
        });
    }

    println!("[Worker Thread] Finished processing for {}. Final local result: {}", thread_name, local_counter);
    local_counter * 2
}

fn main() {
    let initial_state = GameState { record_id: 101 };

    let handle1 = thread::spawn(move || {
        process_replay_data(initial_state, "Replay A");
    });

    let handle2 = thread::spawn(move || {
        process_replay_data(GameState { record_id: 102 }, "Replay B");
    });

    handle1.join().unwrap();
    handle2.join().unwrap();
}

use std::thread;

struct ContextState {
    id: u32,
    data: String
}

fn process_block(initial_context: ContextState) -> ContextState {
    ContextState { id: initial_context.id, data: format!("Processed successfully for ID {}", initial_context.id)
}
}

fn main() {
    let initial_configs = vec![
        ContextState { id: 101, data: "Initial payload A".to_string() },
        ContextState { id: 102, data: "Initial payload B".to_string() },
        ContextState { id: 103, data: "Initial payload C".to_string() },
    ];

    let mut handles = vec![];

    for config in initial_configs {
        let handle = thread::spawn(move || {
            process_block(config)
        });
        handles.push(handle);
    }

    let results: Vec<ContextState> = handles.into_iter().map(|h| h.join().unwrap()).collect();

    for result in results {
        println!("Final State Received: {}", result.data);
    }
}

use std::collections::HashMap;
use std::sync::{Mutex, Arc};

struct StreamStats {
    sum: f64,
    count: u64,
    squared_sum: f64,
}

impl StreamStats {
    fn new() -> Self {
        StreamStats { sum: 0.0, count: 0, squared_sum: 0.0 }
    }

    fn incorporate(&mut self, value: f64) {
        self.sum += value;
        self.count += 1;
        self.squared_sum += value * value;
    }

    fn variance(&self) -> Option<f64> {
        if self.count < 2 {
            return None;
        }
        let n = self.count as f64;
        Some((self.squared_sum - (self.sum * self.sum / n)) / (n - 1.0))
    }
}

fn main() {
    let data_streams: HashMap<String, Arc<Mutex<StreamStats>>> = {
        let mut map = HashMap::new();
        map.insert("TempSensor".to_string(), Arc::new(Mutex::new(StreamStats::new())));
        map.insert("PressureSensor".to_string(), Arc::new(Mutex::new(StreamStats::new())));
        map
    };

    let data1 = vec![20.5, 21.0];
    let data2 = vec![100.1, 99.8, 100.5];

    for (i, &value) in data1.iter().enumerate() {
        let sensor_key = "TempSensor".to_string();
        if let Some(stats_arc) = data_streams.get(&sensor_key) {
            let mut stats = stats_arc.lock().unwrap();
            stats.incorporate(value);
        }
    }

    for (i, &value) in data2.iter().enumerate() {
        let sensor_key = "PressureSensor".to_string();
        if let Some(stats_arc) = data_streams.get(&sensor_key) {
            let mut stats = stats_arc.lock().unwrap();
            stats.incorporate(value);
        }
    }

    println!("Temperature Variance: {:?}", data_streams.get(&"TempSensor".to_string()).unwrap().lock().unwrap().variance());
    println!("Pressure Variance: {:?}", data_streams.get(&"PressureSensor".to_string()).unwrap().lock().unwrap().variance());
}

